namespace sv_f3b93a21bfb04df0b4307858a192c4f3.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_f3b93a21bfb04df0b4307858a192c4f3.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Roman pasta dish with eggs, Pecorino Romano, guanciale, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan, finished with Parmigiano-Reggiano.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken pieces in a creamy, spiced tomato-based sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cheese and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with marinated meat, saffron, and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken, topped with tangy tomatillo salsa verde.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_f3b93a21bfb04df0b4307858a192c4f3.Services
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_isRefreshing && _recipes is not null)
{
    <div class="alert alert-info py-1 px-2 d-inline-block" role="status">
        <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
        Refreshing…
    </div>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p class="mb-1">@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p role="status">
        <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
        Loading recipes…
    </p>
}
else if (_recipes.Count == 0)
{
    <p>No recipes found for this cuisine.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in GetSortedRecipes())
        {
            <div class="col-md-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <p class="card-text">
                            <small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _errorMessage;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only the sort parameter changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load.
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cancellationToken = _loadCts.Token;
        var cuisineId = CuisineId;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineId, cancellationToken);

            // Guard against a cancelled-but-not-yet-thrown token.
            cancellationToken.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Expected when cuisine changed or component disposed — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Cancel();
        _loadCts?.Dispose();
    }
}

