<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_isRefreshing && _recipes is not null)
{
    <div class="alert alert-info py-1 px-2 d-inline-block" role="status">
        <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
